import {decodeJpegBase64} from '../src/ml/decodeJpeg';

// A real 8x8 JPEG (flat grey), base64-encoded. Embedded as a constant so the test needs no node
// Buffer and the strict app tsconfig stays node-free.
const GREY_8X8_JPEG =
  '';

describe('decodeJpegBase64', () => {
  it('decodes a base64 JPEG to RGBA bytes of the expected size', () => {
    const frame = decodeJpegBase64(GREY_8X8_JPEG);
    expect(frame.width).toBe(8);
    expect(frame.height).toBe(8);
    expect(frame.data.length).toBe(8 * 8 * 4);
  });

  it('throws on data that is not a JPEG', () => {
    expect(() => decodeJpegBase64('AAECAwQF')).toThrow();
  });
});
